{
var seed = GetInt(parameters, "seed", context.Seed);
var slatCount = Math.Clamp(GetInt(parameters, "slatCount", 6), 3, 16);
var slatWidth = GetFloat(parameters, "slatWidth", 0.7f);
var slatHeight = GetFloat(parameters, "slatHeight", 0.8f);
var topShape = GetChoice(parameters, "topShape", "flat");
var railCount = Math.Clamp(GetInt(parameters, "railCount", 1), 0, 3);
var woodColor = GetColor(parameters, "woodColor", Color.FromRgb(160, 120, 80));
var darkWood = GetColor(parameters, "darkWoodColor", Color.FromRgb(100, 70, 40));
var colorVar = GetFloat(parameters, "colorVariation", 0.2f);
var wearAmount = GetFloat(parameters, "wearAmount", 0.2f);
var woodGrain = GetFloat(parameters, "woodGrain", 0.5f);
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var wR = woodColor.R / 255f; var wG = woodColor.G / 255f; var wB = woodColor.B / 255f;
var dR = darkWood.R / 255f; var dG = darkWood.G / 255f; var dB = darkWood.B / 255f;

// Pre-compute per-slat data
var slatData = new (float hue, float wear, float grainOffset)[slatCount];
for (var i = 0; i < slatCount; i++)
{
    slatData[i] = (
        (HashToUnit(i * 7, seed, 111) - 0.5f) * colorVar,
        HashToUnit(i * 13, seed + 50, 222),
        HashToUnit(i * 17, seed + 100, 333)
    );
}

// Horizontal rail positions (in UV, top of tile = 0)
var railPositions = new float[railCount];
for (var i = 0; i < railCount; i++)
{
    railPositions[i] = 0.2f + (i + 1f) / (railCount + 1f) * 0.55f;
}

var gapWidth = 1f - slatWidth;
var skyHeight = (1f - slatHeight) * 0.5f;

// Background color (sky/dirt depending on position)
var skyR = 150f / 255f; var skyG = 200f / 255f; var skyB = 255f / 255f;
var groundR = 100f / 255f; var groundG = 180f / 255f; var groundB = 80f / 255f;

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Slat index
    var rawSlat = u * slatCount;
    var slatIdx = ((int)rawSlat % slatCount + slatCount) % slatCount;
    var localU = rawSlat - MathF.Floor(rawSlat);

    // Gap between slats
    var gapHalf = gapWidth * 0.5f;
    var isGap = localU < gapHalf || localU > 1f - gapHalf;

    // Top shape mask
    var topMask = 1f;
    if (v < skyHeight || v > 1f - skyHeight)
    {
        // Above or below fence
        if (!isGap)
        {
            // Check top shape
            var localV = v < skyHeight
                ? v / skyHeight  // 0..1 from top
                : (v - (1f - skyHeight)) / skyHeight; // 0..1 from bottom

            if (v < skyHeight)
            {
                // Top shape
                var localTop = 1f - localV; // 1 at tip, 0 at base
                topMask = topShape switch
                {
                    "pointed" => localU < gapHalf || localU > 1f - gapHalf ? 1f :
                        (localTop > 0f ? 1f - (localU - gapHalf) / (1f - gapWidth) * localTop * 2f : 0f),
                    "rounded" => localU < gapHalf || localU > 1f - gapHalf ? 1f :
                        (1f - localV > 0.1f ? 1f : (localU - gapHalf) / (1f - gapWidth)),
                    "vShape" => localU < gapHalf || localU > 1f - gapHalf ? 1f :
                        (localTop > 0f ? (localU - gapHalf) / (1f - gapWidth) * (1f - localTop) + localTop : 0f),
                    _ => 1f // flat
                };
            }
            else
            {
                // Bottom: return to 1
                topMask = 1f;
            }
        }

        if (topMask < 0.01f)
        {
            // Background behind fence
            var bgR = Lerp(skyR, groundR, v);
            var bgG = Lerp(skyG, groundG, v);
            var bgB = Lerp(skyB, groundB, v * 0.5f + 0.5f);
            buffer.SetPixel(x, y, bgR, bgG, bgB, 1f);
            return;
        }
    }

    float r, g, b;

    if (isGap)
    {
        // Gap between slats — dark
        r = 0.15f; g = 0.1f; b = 0.08f;
    }
    else
    {
        // Slat surface
        var sd = slatData[slatIdx];

        // Base wood color with variation
        r = Math.Clamp(wR + sd.hue, 0f, 1f);
        g = Math.Clamp(wG + sd.hue * 0.8f, 0f, 1f);
        b = Math.Clamp(wB + sd.hue * 0.6f, 0f, 1f);

        // Horizontal rails overlay
        var isRail = false;
        foreach (var rp in railPositions)
        {
            if (v > rp - 0.03f && v < rp + 0.03f)
            {
                isRail = true;
                break;
            }
        }

        if (isRail)
        {
            // Rail is slightly darker
            r *= 0.85f;
            g *= 0.85f;
            b *= 0.85f;
        }

        // Wood grain (vertical streaks)
        if (woodGrain > 0f)
        {
            var grainNoise = TileableFractalNoise(
                u * 3f + sd.grainOffset * 10f, v * 4f,
                Math.Max(1, size / 2), 2, 0.5f, 2.5f, seed + 200);
            var grainVal = (grainNoise - 0.5f) * woodGrain * 0.2f;
            r = Math.Clamp(r + grainVal, 0f, 1f);
            g = Math.Clamp(g + grainVal * 0.85f, 0f, 1f);
            b = Math.Clamp(b + grainVal * 0.7f, 0f, 1f);

            // Knots
            var knotNoise = TileableFractalNoise(
                u * 8f + sd.grainOffset * 20f, v * 6f,
                Math.Max(1, size / 2), 1, 0.5f, 2f, seed + 300);
            if (knotNoise > 0.8f)
            {
                var knot = (knotNoise - 0.8f) / 0.2f * woodGrain;
                r = Math.Clamp(r - knot * 0.3f, 0f, 1f);
                g = Math.Clamp(g - knot * 0.3f, 0f, 1f);
                b = Math.Clamp(b - knot * 0.25f, 0f, 1f);
            }
        }

        // Edge shading: 3D bevel on each slat
        var edgeDist = MathF.Min(localU - gapHalf, 1f - gapHalf - localU);
        edgeDist = MathF.Max(0f, edgeDist / (1f - gapWidth));
        var bevel = 1f - edgeDist * 2f;
        if (bevel > 0.8f)
        {
            var edgeLight = (bevel - 0.8f) / 0.2f * 0.15f;
            r = Math.Clamp(r + edgeLight, 0f, 1f);
            g = Math.Clamp(g + edgeLight * 0.9f, 0f, 1f);
            b = Math.Clamp(b + edgeLight * 0.8f, 0f, 1f);
        }

        // Wear and tear
        if (wearAmount > 0f)
        {
            var wearNoise = TileableFractalNoise(
                u * 5f + slatIdx * 3f, v * 5f,
                Math.Max(1, size / 2), 1, 0.5f, 2f, seed + 400);
            var wearVal = MathF.Pow(MathF.Max(0f, wearNoise * 1.5f - 0.5f), 2f) * wearAmount;

            // Wear: desaturate and lighten at edges
            var wearColor = (wR + wG + wB) / 3f * 1.2f;
            r = Lerp(r, Math.Clamp(wearColor, 0f, 1f), wearVal * 0.5f);
            g = Lerp(g, Math.Clamp(wearColor * 0.95f, 0f, 1f), wearVal * 0.5f);
            b = Lerp(b, Math.Clamp(wearColor * 0.9f, 0f, 1f), wearVal * 0.5f);

            // Nail/screw at each slat center
            if (wearNoise > 0.7f && v > 0.3f && v < 0.7f)
            {
                var nailCenterX = (slatIdx + 0.5f) / slatCount;
                var nailDist = MathF.Abs(u - nailCenterX) * slatCount;
                if (nailDist < 0.06f)
                {
                    var nailBright = 1f - nailDist / 0.06f;
                    r = Math.Clamp(r + nailBright * 0.3f, 0f, 1f);
                    g = Math.Clamp(g + nailBright * 0.3f, 0f, 1f);
                    b = Math.Clamp(b + nailBright * 0.25f, 0f, 1f);
                }
            }
        }
    }

    // Brightness and contrast
    r = Math.Clamp(r + brightness, 0f, 1f);
    g = Math.Clamp(g + brightness, 0f, 1f);
    b = Math.Clamp(b + brightness, 0f, 1f);

    if (MathF.Abs(contrast) > 0.001f)
    {
        var factor = 1f + contrast;
        r = (r - 0.5f) * factor + 0.5f;
        g = (g - 0.5f) * factor + 0.5f;
        b = (b - 0.5f) * factor + 0.5f;
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
